import React, { 
    // useState, 
    // useEffect 
} from 'react';
import Wave from "./Wave";
import RubberText from "./RubberText";

export default function Intro({email, resume, name}) {
    return (
        <section className="intro">
            <div className="intro__text">
                <div className="intro__hello">
                    <h3>Hello, I'm <Wave /></h3>
                    <RubberText className="name" component="h1" text={name ? `${name}.` : "Sanjay Goraniya."} />
                </div>
                <div className="intro__tagline">
                    <h2>I build things for the web. <span className="emoji technologist"></span></h2>
                    <p className="specialty">Back-End &amp; Front-End Developer / AWS Expert</p>
                </div>
            </div>
            <div className="intro__contact">
                <a href={email} target="_blank" className="email-link" rel="noreferrer">
                    Get In Touch
                </a>
                <a href={resume} className="email-link" rel="noreferrer">
                    Get Resume
                </a>
            </div>
        </section>
    );
}