import React, {useState, useEffect} from 'react';
import { BrowserRouter as Router, Switch, Route } from "react-router-dom"; // , Redirect
import initialSite from './data.json';
import {
  Layout,
  Intro,
  Background,
  Skills,
  Experience,
  // FeaturedProjects,
  OtherProjects,
  NotFound
} from './components';

const App = () => {
  const [site, setSite] = useState(initialSite);
  const [loading, setLoading] = useState(true);
  
  useEffect(() => {
    const fetchData = async () => {
      try {
        const result = await fetch(`https://raw.githubusercontent.com/SanjayGoraniya/sanjaygoraniya.github.io/main/siteData.json`);
        const body = await result.json();
        setSite(body);
        setLoading(false);
      } catch(err) {
        setSite(initialSite);
        setLoading(false);
      }
    }
    // setSite(initialSite);
    fetchData();
  }, []);

  useEffect(() => {
    document.body.classList.toggle("siteLoading", loading);
  }, [loading]);
  
  return (
    <Router>
      <Layout siteMetadata={initialSite.siteMetadata} social={(site && site.data && site.data.social) ? site.data.social : []}>
        <Switch>
          <Route exact path="/">
            {loading ? null : <>
              <Intro resume={site.data.resume} email={`mailto:${site.email}`} />
              <Background email={`mailto:${site.email}`} />
              <Skills skills={site.data.skills} />
              <Experience experience={site.data.experience} />
              {/* <FeaturedProjects /> */}
              <OtherProjects otherProjects={site.data.otherProjects} />
            </>}
          </Route>
          <Route>
            {loading ? null : <>
              <NotFound />
            </>}
          </Route>
        </Switch>
      </Layout>
    </Router>
  );
}

export default App;
