import React, { useEffect } from 'react'
// import PropTypes from 'prop-types'
import { Head, Switch, Footer, TopButton } from './index';
import { handleExternalLinks } from '../utils';

const Layout = ({children, siteMetadata, social}) => {

    useEffect(() => {
        handleExternalLinks();
    }, []);
    
    return (
        <>
            <Head siteMetadata={siteMetadata} />
            <Switch />
            {children ? children : null}
            <Footer social={social} />
            <TopButton />
        </>
    )
}

// Layout.propTypes = {

// }

export default Layout;