import React from 'react';
import { RubberText } from './index';

const Footer = ({social}) => {
    return (
        <footer className="footer">
            <div className="footer__copyright">
                <div className="top">
                    <span>Designed &amp; Built by&nbsp;</span>
                </div>
                <div className="bottom">
                    {/* <span>Sanjay Goraniya</span> */}
                    <RubberText className="" component="span" text="Sanjay Goraniya" fadeIn={false} />
                </div>
            </div>
            <div className="footer__links">
                {social && social.map((link, index) => (
                    <a className="underline-link" target="_blank" rel="noreferrer" key={index} title={link.title} href={link.url}>
                        <span className="text">{link.title}</span>
                        <img src={`/img/social/${link.title}.svg`} alt={link.title} />
                    </a>
                ))}
            </div>
        </footer>
    );
}
export default Footer;